const js = String.raw`
(function(){
  const canvas = document.querySelector('[data-mesh]');
  if(canvas){
    const ctx = canvas.getContext('2d');
    let w=0,h=0,dpr=1,pts=[];
    const resize=()=>{dpr=Math.min(window.devicePixelRatio||1,2);w=canvas.clientWidth=innerWidth;h=canvas.clientHeight=innerHeight;canvas.width=w*dpr;canvas.height=h*dpr;ctx.setTransform(dpr,0,0,dpr,0,0);pts=Array.from({length:Math.min(120,Math.floor(w*h/16000))},()=>({x:Math.random()*w,y:Math.random()*h,vx:(Math.random()-.5)*.35,vy:(Math.random()-.5)*.35,r:Math.random()*1.8+.5,c:Math.random()}));};
    const draw=()=>{ctx.clearRect(0,0,w,h);for(const p of pts){p.x+=p.vx;p.y+=p.vy;if(p.x<0||p.x>w)p.vx*=-1;if(p.y<0||p.y>h)p.vy*=-1;ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);ctx.fillStyle=p.c>.72?'#ffe481':p.c>.35?'#74ffd9':'#8fb4ff';ctx.globalAlpha=.78;ctx.fill();}ctx.globalAlpha=.18;ctx.strokeStyle='#74ffd9';for(let i=0;i<pts.length;i++)for(let j=i+1;j<pts.length;j++){const a=pts[i],b=pts[j],dx=a.x-b.x,dy=a.y-b.y,d=Math.hypot(dx,dy);if(d<116){ctx.globalAlpha=(1-d/116)*.18;ctx.beginPath();ctx.moveTo(a.x,a.y);ctx.lineTo(b.x,b.y);ctx.stroke();}}requestAnimationFrame(draw)};addEventListener('resize',resize,{passive:true});resize();draw();
  }
  const launch = document.querySelectorAll('[data-proof-cycle]');
  launch.forEach(btn=>btn.addEventListener('click',()=>{
    const root = btn.closest('section') || document;
    const num = document.querySelector('[data-readiness-number]');
    const label = document.querySelector('[data-readiness-label]');
    const log = document.querySelector('[data-proof-log]');
    const steps = Array.from(document.querySelectorAll('[data-cycle-step]'));
    let n=0; if(log) log.textContent='';
    const messages=['Mission contract committed.','Acceptance criteria normalized.','Evidence planes mapped.','Claims linked to sources.','Verifier mesh assembled.','Human review frontier preserved.','Decision packet sealed.','Receipt replay path ready.'];
    const timer=setInterval(()=>{n+=10;if(num)num.textContent=String(n);if(label)label.textContent=n<100?'Advancing':'Ready';const idx=Math.min(steps.length-1,Math.floor(n/18));steps.forEach((s,i)=>{s.style.borderColor=i<=idx?'rgba(116,255,217,.72)':'rgba(116,255,217,.23)';s.style.boxShadow=i<=idx?'0 0 24px rgba(116,255,217,.14)':'none'});if(log && messages[Math.floor(n/14)-1]) log.textContent += '• '+messages[Math.floor(n/14)-1]+'\n';if(n>=100)clearInterval(timer);},260);
  }));
})();
`;

