function navHtml(active){return nav.map(([href,label])=>`<a class="${label===active?'active':''}" href="${href}">${html(label)}</a>`).join('') + `<a class="cta" href="proof-missions.html">Proof mission</a>`;}
function layout({title,description,active,body}){
  return `<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>${html(title)} · GoalOS Signoff Pro</title><meta name="description" content="${html(description)}"><meta property="og:title" content="${html(title)}"><meta property="og:description" content="${html(description)}"><meta property="og:type" content="website"><meta name="theme-color" content="#06141a"><link rel="stylesheet" href="assets/sme-v2.css"></head><body><canvas class="mesh" data-mesh></canvas><div class="aurora"><i></i><i></i><i></i></div><header class="topbar"><nav class="nav"><a class="brand" href="index.html"><span class="mark"></span><span><b>GoalOS Signoff Pro</b><span>Sovereign Machine Economy</span></span></a><div class="links">${navHtml(active)}</div></nav></header><main>${body}</main><footer class="footer"><div class="footer-inner"><div><strong>GoalOS Signoff Pro</strong><br>Proof-to-acceptance institution · evidence review · signed receipts · reusable capability.</div><div class="subnav"><a href="sme-manifest.json">SME manifest</a><a href="production-manifest.json">Production manifest</a><a href="proof-missions.html">Proof mission</a></div></div></footer><script src="assets/sme-v2.js" defer></script></body></html>`;
}

const gates = [
  ['01','Commit','Mission objective, authority, success criteria, risk, budget, and evidence requirements become a signed institutional commitment.'],
  ['02','Execute','Bounded agents, tools, sources, and policies run inside a traceable work corridor.'],
  ['03','Prove','Outputs are converted into hashes, sources, claims, baselines, costs, risks, verifier notes, and replay paths.'],
  ['04','Review','The verifier mesh and human reviewer inspect what is supported, contradicted, missing, or ready.'],
  ['05','Accept','The client or designated authority admits, rejects, requests changes, or escalates the package.'],
  ['06','Evolve','Accepted work becomes reusable institutional memory only through scoped, replayable capability records.']
];
const modules = [
  ['GoalOSCommit','Aim layer','Institutional intent with objective, constraints, success criteria, authority, risk, budget, and rollback obligations.'],
  ['RunCommitment','Execution corridor','Agent set, tools, policies, context, signer set, budget and latency limits before any work begins.'],
  ['ProofPacket','Proof object','Trace root, output hash, policy decisions, tool history, evals, cost, latency, errors, signatures, and credit assignment.'],
  ['EvalAttestation','Verifier decision','Registered evaluation schema, proof reference, baseline, candidate, verdict, evaluator identity, and signature.'],
  ['SelectionCertificate','Acceptance gate','Admit, reject, canary, promote, pause, or roll back through hard gates rather than vibe-based scoring.'],
  ['EvolutionLedgerEntry','Memory spine','Append-only record of commitments, proofs, attestations, selections, rollout, rollback, and reputation change.']
];
const economyLanes = [
  ['Agents','Bounded workers, reviewers, validators, operators, and institutional roles.','Identity'],
  ['Jobs','Mission commitments, acceptance criteria, tool scopes, and evidence requirements.','Work'],
  ['Validators','Verifier mesh, human review, challenge windows, and evidence-backed decisions.','Proof'],
  ['Memory','Chronicle entries, capability packages, proof history, and replay paths.','Recall'],
  ['Markets','Proof missions, reviewer capacity, future proof-to-payment rails, and capability exchange.','Allocation'],
  ['Governance','Authority boundaries, policy roots, rollback targets, monitoring, and conformance levels.','Control']
];
const docketItems = ['Claims matrix','Source provenance','Verifier report','Risk ledger','Replay path','Decision state'];

function consoleBlock(){
  return `<div class="console"><div class="console-inner"><div class="console-head"><span>Proof-to-acceptance console</span><span>Review mode</span></div><div class="machine-core"><div class="steps">${gates.map(g=>`<div class="step" data-cycle-step><b>${g[0]}</b><div><span>${g[1]}</span><small>${g[2].split('.')[0]}.</small></div></div>`).join('')}</div><div class="core-field"><div class="core-symbol">α</div></div></div><div class="trust-strip"><div><b>✓</b>Evidence mapped</div><div><b>∴</b>Integrity sealed</div><div><b>↻</b>Replay ready</div><div><b>H</b>Human gate</div></div></div></div>`;
}
function gateCards(){ return gates.map(g=>`<article class="gate" data-n="${g[0]}"><h3>${html(g[1])}</h3><p>${html(g[2])}</p></article>`).join(''); }
function moduleCells(){ return modules.map(m=>`<div class="object"><b>${html(m[0])}</b><small>${html(m[2])}</small></div>`).join(''); }
function economyLaneRows(){ return economyLanes.map(l=>`<div class="lane"><b>${html(l[0])}</b><span>${html(l[1])}</span><em>${html(l[2])}</em></div>`).join(''); }
function docketRing(){ return `<div class="docket-ring">${docketItems.map(x=>`<span>${html(x)}</span>`).join('')}</div>`; }

write(path.join(SITE,'sovereign-machine-economy.html'), layout({
  title:'Sovereign Machine Economy', active:'Sovereign Economy', description:'GoalOS AGIALPHA Ascension as a proof-bearing economy for AI-delivered work.',
  body:`<section class="section hero"><div><div class="eyebrow">GoalOS AGIALPHA Ascension</div><h1>Sovereign <span class="accent">Machine</span> Economy.</h1><p class="lead">From mission to evidence, from evidence to acceptance, from acceptance to reusable capability.</p><p class="sub">A product architecture for turning AI-delivered work into commitments, evidence dockets, review decisions, signed receipts, replay paths, and institutional memory.</p><div class="buttons"><a class="button primary" href="proof-os.html">Enter the Proof OS</a><a class="button" href="constitution.html">Inspect the constitution</a></div><div class="metrics"><div class="metric"><b>6</b><span>acceptance gates</span></div><div class="metric"><b>12</b><span>evidence planes</span></div><div class="metric"><b>1</b><span>human frontier</span></div><div class="metric"><b>∞</b><span>receipt replay</span></div></div></div>${consoleBlock()}</section><section class="section"><div class="eyebrow">Operating thesis</div><h2>Machine work becomes institutional when it can be inspected.</h2><p class="lead copy-tight">GoalOS Signoff Pro is the acceptance surface: it transforms deliverables into proof packages and gives clients, reviewers, and systems a stable record of what was requested, delivered, evidenced, accepted, and preserved.</p><div class="architecture-band">${gateCards()}</div></section><section class="section"><div class="grid-2"><div class="card big"><div class="kicker">Reimplementation map</div><h2>Agent. Node. Jobs. One proof economy.</h2><p>The prior META‑AGENTIC α‑AGI, AGI Alpha Node, and AGI Jobs surfaces are re-expressed as a single product posture: evidence-state orchestration, bounded run/replay, proof-to-acceptance work, and capability memory.</p><div class="subnav"><a href="machine-economy.html">Machine economy</a><a href="proof-missions.html">Proof missions</a></div></div><div class="card"><div class="stack-lanes"><div class="lane"><b>META-AGENTIC α‑AGI</b><span>Mission decomposition, verifier routing, decision-state formation, capability packaging.</span><em>Orchestrate</em></div><div class="lane"><b>AGI Alpha Node v0</b><span>Runtime identity, trace roots, output hashes, validator gates, replay paths.</span><em>Run</em></div><div class="lane"><b>AGI Jobs v0 / v2</b><span>Jobs become commitments; submissions become dockets; receipts become institutional records.</span><em>Settle-ready</em></div></div></div></div></section><section class="section"><div class="visual-callout"><h3>Institutional compounding begins with acceptance.</h3><p>Accepted work can become a capability only when the mission, evidence, review, decision, and replay path are all preserved. The result is not another landing page. It is a public front door for a proof-bearing machine economy.</p></div></section>`
}));

write(path.join(SITE,'proof-os.html'), layout({
  title:'Proof OS', active:'Proof OS', description:'The Proof OS converts objectives into evidence-backed governed decision states.',
  body:`<section class="section hero"><div><div class="eyebrow">Proof OS</div><h1>Set the objective. <span class="accent">Earn</span> the decision.</h1><p class="lead">Mission briefs become contracts. Outputs become evidence. Evidence becomes a decision state that teams can inspect, defend, act on, or reject.</p><p class="sub">The system’s job is not to produce more text. It moves one objective from uncertainty to justified action through a visible proof corridor.</p><div class="buttons"><button class="button primary" data-proof-cycle>Launch proof cycle</button><a class="button" href="proof-missions.html">Request a proof mission</a></div></div><div class="proof-theatre"><div><div class="kicker">Mission control</div><h2>Proof cycle</h2><p class="sub">A local theatre advances through the same product logic: commission, submit, map, review, accept, receipt.</p><div class="control-log" data-proof-log>System ready. Awaiting bounded mission.</div></div><div><div class="readiness"><div><div class="number" data-readiness-number>0</div><small data-readiness-label>Awaiting mission</small></div></div><div class="steps" style="margin-top:16px">${gates.map(g=>`<div class="step" data-cycle-step><b>${g[0]}</b><div><span>${g[1]}</span><small>${g[2].split('.')[0]}.</small></div></div>`).join('')}</div></div></div></section><section class="section"><div class="eyebrow">Governed decision state</div><h2>The deliverable is a decision state, not a document.</h2><div class="docket"><div class="card"><p class="lead">A serious mission package contains the objective, claims matrix, source provenance, contradiction register, risk ledger, verifier report, executive brief, action graph, Chronicle entry, and capability package.</p><div class="terminal">MissionContract + ClaimsMatrix + SourceProvenance\n+ ContradictionRegister + EvidenceDocket + VerifierReport\n+ RiskLedger + DecisionState + ActionGraph\n+ ChronicleEntry + ClaimBoundaryPass + QAPass\n= DONE</div></div>${docketRing()}</div></section><section class="section"><div class="grid-3"><div class="card"><h3>Claims become inspectable.</h3><p>Each major claim points to evidence, uncertainty, contradiction, or reviewer attention.</p></div><div class="card"><h3>Risks become visible.</h3><p>Risk, cost, latency, freshness, assumptions, and boundary conditions are part of the record.</p></div><div class="card"><h3>Decisions become replayable.</h3><p>The receipt keeps the accepted version, evidence fingerprints, signer, timestamp, and verification path.</p></div></div></section>`
}));

write(path.join(SITE,'machine-economy.html'), layout({
  title:'Machine Economy', active:'Machine Economy', description:'Agents, jobs, validators, memory, markets, settlement rails, and governance as a proof-bearing work substrate.',
  body:`<section class="section hero compact"><div><div class="eyebrow">Machine Economy</div><h1>Agents become useful when <span class="accent">work</span> becomes proof.</h1><p class="lead">The economy is not a swarm. It is a controlled market surface for bounded jobs, evidence packets, reviewer decisions, reusable capability, and settlement-grade records.</p><div class="buttons"><a class="button primary" href="proof-missions.html">Start with one proof mission</a><a class="button" href="dossier.html">Inspect the dossier</a></div></div>${consoleBlock()}</section><section class="section"><div class="eyebrow">Six institutional rails</div><h2>A substrate above models.</h2><div class="stack-lanes" style="margin-top:32px">${economyLaneRows()}</div></section><section class="section"><div class="grid-2"><div class="card"><h2>Work rail</h2><p>Requests become commitments; execution becomes bounded runs; outputs become artifacts; claims become evidence; evidence becomes decisions.</p><div class="terminal">Request → Commit → Execute → Proof → Validate → Accept → Chronicle</div></div><div class="card"><h2>Capability rail</h2><p>Accepted records feed a capability library: initiation conditions, workflow policy, validator history, risk class, cost profile, rollback path, and replay instructions.</p><div class="terminal">Accepted work → Proof history → Reusable capability → Future routing context</div></div></div></section><section class="section"><div class="eyebrow">Market topology</div><h2>Useful markets require proof, identity, and review.</h2><div class="grid-3"><div class="card"><h3>Job market</h3><p>Bounded deliverables, acceptance criteria, deadlines, and review authority.</p></div><div class="card"><h3>Validator market</h3><p>Reviewer capacity, evaluation schemas, challenge windows, and attestations.</p></div><div class="card"><h3>Capability market</h3><p>Reusable artifacts become discoverable by evidence history, scope, and replay path.</p></div></div></section>`
}));

write(path.join(SITE,'constitution.html'), layout({
  title:'AEP-001 Constitution', active:'Constitution', description:'The proof-carrying object model and selection law behind GoalOS Signoff Pro.',
  body:`<section class="section hero compact"><div><div class="eyebrow">AEP-001 Constitution</div><h1>Aim. Act. Prove. <span class="accent">Evolve.</span></h1><p class="lead">AEP-001 is the object model that turns institutional intent into proof-carrying evolution: commitments, runs, packets, attestations, certificates, ledgers, and dockets.</p><div class="buttons"><a class="button primary" href="proof-os.html">Enter Proof OS</a><a class="button" href="machine-economy.html">Inspect economy</a></div></div><div class="diagram"><div class="kicker">AEP-001 object graph</div><div class="object-graph" style="margin-top:20px">${moduleCells()}</div></div></section><section class="section"><div class="eyebrow">Selection law</div><h2>Scores advise. Gates decide.</h2><div class="grid-2"><div class="card"><p class="lead">The Proof Gradient is not a popularity score. It is a gate stack: proof integrity, evaluation pass, risk threshold, rollback readiness, scope authorization, challenge clearance, and human-review state.</p><div class="terminal">Promote(U) iff\n  ProofValid(U)\n  AND EvalPass(U)\n  AND Risk(U) <= ρ\n  AND RollbackReady(U)\n  AND ScopeAuthorized(U)\n  AND ChallengeWindowCleared(U)</div></div><div class="card"><h3>Proof before propagation</h3><p>A candidate cannot influence future work because it sounds persuasive. It earns scope through evidence, reviewer decision, replay path, and rollback ability.</p><h3>Private intelligence, public proof</h3><p>Private prompts, traces, customer data, and raw documents remain controlled; public commitments, hashes, attestations, and receipts stay verifiable.</p></div></div></section><section class="section"><div class="eyebrow">Conformance ladder</div><h2>From schema-valid to cross-institutional.</h2><div class="table"><div class="row"><div><b>L0</b></div><div><span>Schema-valid objects and generated source.</span></div><div><em>Start</em></div></div><div class="row"><div><b>L1–L2</b></div><div><span>Proof-emitting runs with evaluation gates and baseline comparisons.</span></div><div><em>Prove</em></div></div><div class="row"><div><b>L3–L4</b></div><div><span>Rollbackable, attestable decisions with reviewer signatures.</span></div><div><em>Govern</em></div></div><div class="row"><div><b>L5–L6</b></div><div><span>Production-governed canaries and cross-institutional proof-carrying artifacts.</span></div><div><em>Evolve</em></div></div></div></section><section class="section"><div class="visual-callout"><h3>The constitution is the product posture.</h3><p>It gives Signoff Pro a rigorous spine: the user sees acceptance; the system records commitments, proofs, attestations, decisions, and replayable capability boundaries.</p></div></section>`
}));

write(path.join(SITE,'proof-missions.html'), layout({
  title:'Founding Proof Missions', active:'Proof Missions', description:'Proof missions turn a high-stakes AI deliverable into an evidence-backed governed decision state.',
  body:`<section class="section hero compact"><div><div class="eyebrow">Founding proof missions</div><h1>Bring one serious AI delivery into <span class="accent">Signoff.</span></h1><p class="lead">A proof mission converts a real deliverable into a mission contract, evidence docket, verifier report, risk ledger, decision state, action graph, Chronicle entry, and signed receipt.</p><div class="buttons"><a class="button primary" href="mailto:${html(config.pilotEmail)}?subject=GoalOS%20Signoff%20Pro%20Proof%20Mission">Request proof mission access</a><a class="button" href="sovereign-machine-economy.html">Inspect the economy</a></div></div><div class="console"><div class="console-inner"><div class="console-head"><span>Founding mission corridor</span><span>48-hour wedge</span></div><div class="core-field"><div class="core-symbol">✓</div></div><div class="trust-strip"><div><b>1</b>Objective</div><div><b>12</b>Evidence planes</div><div><b>1</b>Decision state</div><div><b>∞</b>Replay</div></div></div></div></section><section class="section"><div class="eyebrow">Best first missions</div><h2>Start where acceptance already matters.</h2><div class="grid-3"><div class="card"><h3>AI research or strategy</h3><p>Move an AI-assisted report from “looks plausible” to evidence-backed acceptance.</p></div><div class="card"><h3>Automation handoff</h3><p>Record what was delivered, tested, reviewed, accepted, and preserved for future maintenance.</p></div><div class="card"><h3>Grant or milestone review</h3><p>Give reviewers a structured decision state instead of a loose deliverable bundle.</p></div></div></section><section class="section"><div class="grid-2"><div class="visual-callout"><h3>The strongest proof mission is not the biggest report.</h3><p>It is the mission that makes one decision inspectable, defensible, and ready for human authority.</p></div><div class="card"><h3>Contact</h3><p>For private beta access, use <strong>${html(config.pilotEmail)}</strong>.</p><p class="source-note">The public site should sell the product by showing the workflow: objective, evidence, review, authority, receipt, replay.</p></div></div></section>`
}));


function appendToPage(file, fragment){
  const target = path.join(SITE,file);
  let text = fs.readFileSync(target,'utf8');
  text = text.replace('</main>', `${fragment}</main>`);
  fs.writeFileSync(target,text);
}

appendToPage('sovereign-machine-economy.html', `<section class="section"><div class="eyebrow">Institutional value chain</div><h2>From verified work to reusable institutional capacity.</h2><div class="grid-4"><div class="card"><h3>Verified work</h3><p>Accepted deliverables become durable records with evidence, review, timestamps, and replayable context.</p></div><div class="card"><h3>Reusable capability</h3><p>Patterns that survive review can become templates, workflows, playbooks, and future mission starting points.</p></div><div class="card"><h3>Capacity allocation</h3><p>Leadership can decide which capabilities to retain, share, license, repeat, improve, or retire.</p></div><div class="card"><h3>Governed memory</h3><p>The Chronicle preserves what worked, what failed, what changed, and what requires human escalation.</p></div></div></section><section class="section"><div class="grid-2"><div class="diagram"><div class="kicker">Compounding chain</div><div class="terminal">Model capability\n  → bounded work\n    → evidence docket\n      → reviewer decision\n        → signed receipt\n          → reusable capability\n            → stronger future work</div></div><div class="card"><h2>Why this matters</h2><p>Organizations do not scale by accepting every AI output. They scale by preserving the few outputs that survive evidence, review, and operational memory. Sovereign Machine Economy is the public architecture for that discipline.</p></div></div></section>`);

appendToPage('proof-os.html', `<section class="section"><div class="eyebrow">Evidence Docket anatomy</div><h2>Every important claim gets a room.</h2><div class="grid-3"><div class="card"><h3>Claim support</h3><p>Major assertions are mapped to source evidence, reviewer notes, unsupported gaps, and uncertainty.</p></div><div class="card"><h3>Verifier mesh</h3><p>Source reality, contradiction coverage, freshness, risk, and recommendation traceability are brought into the review surface.</p></div><div class="card"><h3>Decision package</h3><p>The output becomes a reviewable state with executive brief, action graph, risk ledger, and acceptance boundary.</p></div></div></section><section class="section"><div class="grid-2"><div class="card"><h2>Run-to-DONE machine</h2><p>If a claim lacks evidence, the workflow returns to evidence gathering. If a contradiction is unresolved, it returns to analysis. If the risk ledger is missing, it returns to risk pass. If the claim boundary fails, it revises.</p></div><div class="diagram"><div class="kicker">DONE condition</div><div class="terminal">MissionContract\nClaimsMatrix\nSourceProvenance\nContradictionRegister\nEvidenceDocket\nVerifierReport\nRiskLedger\nDecisionState\nActionGraph\nChronicleEntry</div></div></div></section><section class="section"><div class="visual-callout"><h3>The interface is the proof room.</h3><p>GoalOS should make every accepted AI deliverable easier to inspect than a report, easier to defend than a chat transcript, and easier to reuse than a folder of disconnected files.</p></div></section>`);

appendToPage('machine-economy.html', `<section class="section"><div class="eyebrow">Settlement-grade shape</div><h2>Proof-to-acceptance now. Proof-to-payment when the gates are ready.</h2><div class="table"><div class="row"><div><b>Request</b></div><div><span>Mission, acceptance tests, risk class, policy context, and evidence requirements.</span></div><div><em>Commit</em></div></div><div class="row"><div><b>Execute</b></div><div><span>Bounded work with tools, context, trace roots, output hashes, and costs.</span></div><div><em>Run</em></div></div><div class="row"><div><b>Validate</b></div><div><span>Reviewer and evaluator attestations, challenge windows, replay paths, and signed decisions.</span></div><div><em>Gate</em></div></div><div class="row"><div><b>Chronicle</b></div><div><span>Accepted receipts and capability records that can inform future work under scoped authority.</span></div><div><em>Memory</em></div></div></div></section><section class="section"><div class="grid-3"><div class="card"><h3>Identity layer</h3><p>Actors are represented by roles, permissions, signer identity, and review authority.</p></div><div class="card"><h3>Proof layer</h3><p>Work becomes evidence through trace roots, output hashes, decision records, cost/risk ledgers, and replay.</p></div><div class="card"><h3>Governance layer</h3><p>Promotion is scoped by evaluation, rollback readiness, challenge clearance, and human authorization.</p></div></div></section><section class="section"><div class="visual-callout"><h3>The market does not begin with money. It begins with acceptance.</h3><p>Once work is accepted in a trusted, replayable format, the future rails for reputation, rewards, settlement, and capability exchange become architecturally legible.</p></div></section>`);

appendToPage('constitution.html', `<section class="section"><div class="eyebrow">Public-private proof boundary</div><h2>Publish proof. Protect intelligence.</h2><div class="grid-2"><div class="card"><h3>Public proof</h3><p>Commitment hashes, artifact IDs, proof roots, evidence pointers, evaluator attestations, selection certificates, rollout and rollback receipts, and public-safe dockets.</p></div><div class="card"><h3>Private intelligence</h3><p>Prompts, raw traces, private documents, customer data, privileged evaluator notes, internal approvals, secret values, and confidential workpapers remain controlled.</p></div></div></section><section class="section"><div class="eyebrow">Threat model</div><h2>False proof, collusion, reward hacking, leakage, capture, rollback failure.</h2><div class="grid-3"><div class="card"><h3>Proof integrity</h3><p>Signatures, trace roots, replay, evidence pointers, and evaluator attestations make claims contestable.</p></div><div class="card"><h3>Evaluation robustness</h3><p>Diverse evaluators, challenge windows, negative controls, baselines, and delayed outcomes reduce false acceptance.</p></div><div class="card"><h3>Rollback discipline</h3><p>Every promoted capability needs a recovery target, monitoring condition, incident path, and revision history.</p></div></div></section><section class="section"><div class="eyebrow">Evidence Docket 6.1</div><h2>A public-safe proof room, not a pitch deck.</h2><div class="docket"><div class="card"><p class="lead">The docket ties claims to baselines, manifests, proof packets, evals, costs, risks, and public/private boundaries. It is what makes a claim inspectable.</p></div>${docketRing()}</div></section>`);

appendToPage('proof-missions.html', `<section class="section"><div class="eyebrow">Mission package</div><h2>What a founding proof mission should deliver.</h2><div class="architecture-band"><article class="gate" data-n="01"><h3>Mission contract</h3><p>Objective, decision to support, acceptance criteria, risk class, allowed sources, and done condition.</p></article><article class="gate" data-n="02"><h3>Evidence docket</h3><p>Claims matrix, source provenance, verifier report, risk ledger, contradictions, and replay path.</p></article><article class="gate" data-n="03"><h3>Decision state</h3><p>Executive brief, reviewer notes, decision options, action graph, and acceptance boundary.</p></article><article class="gate" data-n="04"><h3>Signed receipt</h3><p>Accepted version, evidence fingerprints, signoff decision, timestamp, and verification path.</p></article><article class="gate" data-n="05"><h3>Chronicle entry</h3><p>What was learned, what becomes reusable, and what must remain under review.</p></article><article class="gate" data-n="06"><h3>Capability package</h3><p>Reusable template, workflow, checklist, or playbook for future missions.</p></article></div></section><section class="section"><div class="grid-2"><div class="card"><h2>Ideal pilots</h2><ul><li>AI research or strategy deliverable</li><li>Automation implementation milestone</li><li>Software feature handoff</li><li>Grant or bounty milestone review</li><li>Procurement or partnership diligence</li><li>Internal AI pilot acceptance</li></ul></div><div class="visual-callout"><h3>Success signal</h3><p>Five real Signoffs attempted. Three completed end-to-end. Two users say they would use it again. Zero broken receipts. Zero ambiguous acceptance decisions.</p><div class="buttons"><a class="button primary" href="mailto:info@quebec.ai?subject=GoalOS%20Signoff%20Pro%20Proof%20Mission">Request proof mission access</a></div></div></div></section>`);


appendToPage('proof-missions.html', `<section class="section"><div class="eyebrow">48-hour operating model</div><h2>One serious objective. One reviewable decision state.</h2><div class="table"><div class="row"><div><b>Hour 0–4</b></div><div><span>Clarify objective, acceptance criteria, claim boundaries, source requirements, and review authority.</span></div><div><em>Contract</em></div></div><div class="row"><div><b>Hour 4–24</b></div><div><span>Collect evidence, map claims, surface contradictions, assemble risk and cost ledgers, and build verifier notes.</span></div><div><em>Docket</em></div></div><div class="row"><div><b>Hour 24–40</b></div><div><span>Prepare decision brief, action graph, uncertainty register, and reviewer-ready acceptance packet.</span></div><div><em>Review</em></div></div><div class="row"><div><b>Hour 40–48</b></div><div><span>Record decision, issue Mission Receipt, preserve replay path, and extract reusable capability.</span></div><div><em>Receipt</em></div></div></div></section><section class="section"><div class="visual-callout"><h3>Founding offer</h3><p>Give GoalOS one high-stakes AI-delivered work package. Receive a proof-backed acceptance record that shows what was requested, what was delivered, what evidence supports it, what remains uncertain, and who accepted it.</p></div></section>`);


appendToPage('sovereign-machine-economy.html', `<section class="section"><div class="eyebrow">Operating architecture</div><h2>Meta-agentic cognition, Alpha nodes, AGI Jobs, and Signoff receipts converge here.</h2><div class="grid-3"><div class="card"><h3>Meta-agentic cognition</h3><p>The orchestration layer decomposes objectives, routes evidence states, prepares verifier work, and packages reviewer-ready decision states.</p></div><div class="card"><h3>Alpha nodes</h3><p>The runtime layer represents bounded execution: identity, trace roots, output hashes, observability, replay corridors, and fail-closed operations.</p></div><div class="card"><h3>AGI Jobs</h3><p>The work layer expresses the commercial primitive: requests, commitments, proof packets, validation, acceptance, receipts, and future settlement-grade records.</p></div></div></section><section class="section"><div class="eyebrow">Institutional memory</div><h2>A machine economy needs an evidence spine.</h2><div class="table"><div class="row"><div><b>Mission</b></div><div><span>The objective, authority, and acceptance criteria become durable before work begins.</span></div><div><em>Aim</em></div></div><div class="row"><div><b>Work</b></div><div><span>Bounded execution produces artifacts, traces, hashes, tool decisions, and cost/risk records.</span></div><div><em>Act</em></div></div><div class="row"><div><b>Proof</b></div><div><span>Evidence dockets turn outputs into reviewable institutional proof rooms.</span></div><div><em>Prove</em></div></div><div class="row"><div><b>Capability</b></div><div><span>Accepted receipts can seed scoped reusable memory and future governed work.</span></div><div><em>Evolve</em></div></div></div></section>`);

appendToPage('proof-os.html', `<section class="section"><div class="eyebrow">Objective → proof → decision state</div><h2>Objective → proof → decision state is the product spine.</h2><div class="grid-3"><div class="card"><h3>Objective</h3><p>The mission begins with a decision that needs support, a success condition, a failure condition, and a reviewer.</p></div><div class="card"><h3>Proof</h3><p>The system assembles an Evidence Docket 6.1 with claims, sources, contradictions, verifier notes, risks, costs, and replay.</p></div><div class="card"><h3>Decision state</h3><p>The reviewer receives an inspectable package: accept, request changes, reject, or escalate.</p></div></div></section><section class="section"><div class="eyebrow">Until-DONE mission cycle</div><h2>Until-DONE mission cycle.</h2><div class="architecture-band"><article class="gate" data-n="01"><h3>Created</h3><p>Mission and authority are defined.</p></article><article class="gate" data-n="02"><h3>Commit</h3><p>Criteria and constraints become a commitment.</p></article><article class="gate" data-n="03"><h3>Claims</h3><p>Outputs are decomposed into inspectable claims.</p></article><article class="gate" data-n="04"><h3>Verify</h3><p>Sources, contradictions, risks, and freshness are checked.</p></article><article class="gate" data-n="05"><h3>Docket</h3><p>The review room is assembled.</p></article><article class="gate" data-n="06"><h3>Decision</h3><p>Reviewer authority seals the state.</p></article></div></section>`);

appendToPage('machine-economy.html', `<section class="section"><div class="eyebrow">Model substrate vs. organizational substrate</div><h2>Model substrate vs. organizational substrate.</h2><div class="grid-2"><div class="card"><h3>Model substrate</h3><p>Tokens, attention, parameters, data, and compute scale capability inside models.</p></div><div class="card"><h3>Organizational substrate</h3><p>Agents, jobs, validators, memory, incentives, markets, settlement, governance, and capacity allocation scale capability across institutions.</p></div></div></section><section class="section"><div class="eyebrow">Proof-grade work chain</div><h2>Proof-grade work chain.</h2><div class="terminal">Request → Commit → Execute → Proof → Validate → Accept → Chronicle\nIdentity → Authority → Tool scope → Evidence → Review → Receipt → Capability</div></section><section class="section"><div class="eyebrow">Economy control plane</div><h2>The flywheel.</h2><div class="grid-4"><div class="card"><h3>Verified labor</h3><p>Accepted work with evidence and replay.</p></div><div class="card"><h3>Reusable capability</h3><p>Patterns, templates, workflows, and artifacts that survive review.</p></div><div class="card"><h3>Productive capacity</h3><p>Better work, faster reviews, lower proof debt, and clearer acceptance.</p></div><div class="card"><h3>Stronger future work</h3><p>Institutional memory improves the next mission.</p></div></div></section>`);

appendToPage('constitution.html', `<section class="section"><div class="eyebrow">Proof-of-Evolution Constitution</div><h2>Proof-of-Evolution Constitution.</h2><p class="lead">The Unified doctrine is Aim → Act → Prove → Evolve. The internal object cycle is Commit → Execute → Prove → Evolve. The interface makes this doctrine visible as an acceptance architecture.</p></section><section class="section"><div class="eyebrow">Object graph</div><h2>Object graph.</h2><div class="object-graph">${moduleCells()}</div></section><section class="section"><div class="eyebrow">Selection Gate calculus</div><h2>Selection Gate calculus.</h2><div class="terminal">ProofValid ∧ EvalPass ∧ Risk≤ρ ∧ RollbackReady ∧ ScopeAuthorized ∧ ChallengeWindowCleared → SelectionCertificate</div></section><section class="section"><div class="eyebrow">Conformance ladder</div><h2>Conformance ladder.</h2><div class="table"><div class="row"><div><b>L0</b></div><div><span>Schema-valid commitments and generated source.</span></div><div><em>Source</em></div></div><div class="row"><div><b>L1</b></div><div><span>Runs emit proof packets with trace roots, output hashes, cost, latency, and signatures.</span></div><div><em>Proof</em></div></div><div class="row"><div><b>L2–L4</b></div><div><span>Evaluations, rollback, and attestation become mandatory.</span></div><div><em>Gate</em></div></div><div class="row"><div><b>L5–L6</b></div><div><span>Production-governed and cross-institutional proof-carrying artifacts.</span></div><div><em>Scale</em></div></div></div></section>`);

appendToPage('proof-missions.html', `<section class="section"><div class="eyebrow">Ideal first pilots</div><h2>Ideal first pilots.</h2><div class="grid-3"><div class="card"><h3>Strategy deliverable</h3><p>Market, product, policy, or competitive intelligence where the client needs acceptance evidence.</p></div><div class="card"><h3>Automation milestone</h3><p>AI-assisted workflow implementation where tests, screenshots, constraints, and limitations must be preserved.</p></div><div class="card"><h3>Grant milestone</h3><p>Reviewer-ready work that needs a clear record of what was delivered and what was accepted.</p></div></div></section><section class="section"><div class="eyebrow">What the mission produces</div><h2>What the mission produces.</h2><div class="table"><div class="row"><div><b>Evidence Docket</b></div><div><span>Claims, source provenance, contradictions, verifier report, risk and cost ledgers.</span></div><div><em>Proof</em></div></div><div class="row"><div><b>Decision state</b></div><div><span>Executive brief, action graph, review notes, acceptance boundary, and change-request path.</span></div><div><em>Review</em></div></div><div class="row"><div><b>Mission Receipt</b></div><div><span>Accepted version, evidence fingerprints, signer, timestamp, and replay path.</span></div><div><em>Record</em></div></div><div class="row"><div><b>Capability package</b></div><div><span>Reusable checklist, template, workflow, or playbook for future related work.</span></div><div><em>Reuse</em></div></div></div></section>`);

function injectIndex(){
  const indexPath = path.join(SITE,'index.html');
  if(!fs.existsSync(indexPath)) return;
  let s = fs.readFileSync(indexPath,'utf8');
  if(!s.includes('sme-v2.css')) s = s.replace('</head>', '<link rel="stylesheet" href="assets/sme-v2.css"></head>');
  if(!s.includes('sme-v2.js')) s = s.replace('</body>', '<script src="assets/sme-v2.js" defer></script></body>');
  if(!s.includes('Sovereign Machine Economy') || !s.includes('sovereign-machine-economy.html')){
    const band = `<section class="section"><div class="visual-callout"><div class="eyebrow">GoalOS AGIALPHA Ascension</div><h2>Sovereign Machine Economy</h2><p>The Signoff product now opens into the broader GoalOS architecture: mission commitments, evidence dockets, verifier mesh, human authority, signed receipts, and reusable capability.</p><div class="buttons"><a class="button primary" href="sovereign-machine-economy.html">Enter Sovereign Economy</a><a class="button" href="constitution.html">Inspect Constitution</a></div></div></section>`;
    s = s.replace('</main>', `${band}</main>`);
  }
  fs.writeFileSync(indexPath,s);
}
injectIndex();

const pages = ['sovereign-machine-economy.html','proof-os.html','machine-economy.html','constitution.html','proof-missions.html'];
const sitemapPages = ['index.html','platform.html','theatre.html','architecture.html','trust.html','pilot.html','dossier.html',...pages].filter((p,i,a)=>a.indexOf(p)===i);
write(path.join(SITE,'sitemap.xml'), `<?xml version="1.0" encoding="UTF-8"?><urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">${sitemapPages.map(file=>`<url><loc>${config.productionUrl}${file}</loc></url>`).join('')}</urlset>`);
write(path.join(SITE,'robots.txt'), `User-agent: *\nAllow: /\nSitemap: ${config.productionUrl}sitemap.xml\n`);

const publicFiles = listFiles(SITE).filter(f=>fs.statSync(f).isFile()).sort();
const hashes = Object.fromEntries(publicFiles.map(file=>[path.relative(SITE,file).replaceAll('\\','/'), sha256File(file)]));
const siteHash = sha256Text(Object.entries(hashes).map(([k,v])=>`${k}:${v}`).join('\n'));
const manifest = { product: config.product, repository: config.repository, productionUrl: config.productionUrl, version: VERSION, generatedAt: GENERATED_AT, githubSha: process.env.GITHUB_SHA || 'local', githubRunId: process.env.GITHUB_RUN_ID || 'local', pages, siteHash, hashes, artifactBoundary: 'public static pages only; no private workspace or secrets' };
write(path.join(SITE,'sme-manifest.json'), JSON.stringify(manifest,null,2)+'\n');
const pmPath = path.join(SITE,'production-manifest.json');
let prod = {};
if(fs.existsSync(pmPath)){ try{ prod = readJson(pmPath); }catch{} }
prod.sovereignMachineEconomy = { version: VERSION, generatedAt: GENERATED_AT, pages, siteHash };
write(pmPath, JSON.stringify(prod,null,2)+'\n');

const forbidden = ['.env','BEGIN PRIVATE KEY','SUPABASE'+'_SERVICE_ROLE','STRIPE'+'_SECRET_KEY','sk'+'_live_','wallet'+' private key','seed'+' phrase','mne'+'monic','Mainnet settlement is live','AGIALPHA staking is live','user funds authorized','autonomous acceptance','realized ASI','superintelligence achieved','The public site is designed','intentionally cinematic'];
const hits=[];
for(const file of publicFiles){
  const rel = path.relative(SITE,file).replaceAll('\\','/');
  const text = fs.readFileSync(file,'utf8');
  for(const marker of forbidden){ if(text.includes(marker)) hits.push(`${rel}: ${marker}`); }
}
if(hits.length){ console.error('Public artifact boundary violation:\n'+hits.join('\n')); process.exit(1); }
for(const page of pages){
  const file = path.join(SITE,page);
  if(!fs.existsSync(file)) throw new Error(`Missing generated page ${page}`);
  const text = fs.readFileSync(file,'utf8');
  if(text.length < 8000) throw new Error(`Generated page too thin: ${page} (${text.length} bytes)`);
  if(!text.includes('sme-v2.css') || !text.includes('sme-v2.js')) throw new Error(`Missing flagship assets in ${page}`);
}
console.log(`Sovereign Machine Economy flagship pages generated (${VERSION}): ${pages.join(', ')}`);
console.log(`Site hash: ${siteHash}`);
